onTextChanged:
(function() {
  if (!inp_customer_name.text) {
    showAlert('Customer name is required', 'warning');
    return;
  }

  qry_customer_create.run()
    .then(function(result) {

      // Run site contact query if those fields are filled
      if (inp_site_contact.text || inp_site_phone.text || inp_site_email.text) {
        qry_site_create.run()
          .then(function() {
            showAlert(inp_customer_name.text + ' created successfully', 'success');
            navigateTo('Customers', {}, 'SAME_WINDOW');
          })
          .catch(function() {
            showAlert('Customer saved but site contact failed', 'warning');
            navigateTo('Customers', {}, 'SAME_WINDOW');
          });
      } else {
        showAlert(inp_customer_name.text + ' created successfully', 'success');
        navigateTo('Customers', {}, 'SAME_WINDOW');
      }

    })
    .catch(function(error) {
      showAlert('Failed to create customer — ' + error.message, 'error');
    });
})();
